// ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
// services/api.js  ΓÇö  PrepFlow AI  ┬╖  Data-fetching layer
//
// Data flow (priority order):
//   1. Firestore cache  ΓåÆ skip API calls if today's data is already stored
//   2. n8n webhook      ΓåÆ PRIMARY source for question + hint + news
//   3. Gemini AI        ΓåÆ FALLBACK for question + hint  (if n8n fails)
//   4. NewsAPI          ΓåÆ FALLBACK for news             (if n8n fails)
//   5. Local bank       ΓåÆ LAST RESORT fallback question bank (always works)
//
// Exports used by UI:
//   fetchDashboardData(topic, company)  ΓåÆ { question, hint, difficulty, topic, company, articles[] }
//   fetchMoreNews()                      ΓåÆ articles[]   (refresh button)
//   checkAnswer(question, answer, mode, language) ΓåÆ { correct, feedback, suggestion }
// ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

import { db } from "./firebase";
import { doc, getDoc, setDoc, serverTimestamp } from "firebase/firestore";

// ΓöÇΓöÇ API endpoints & keys ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

/** PRIMARY: n8n webhook ΓÇö returns { question, hint, news }
 *  In development:  requests go through the Vite dev proxy (/api/n8n ΓåÆ n8n webhook)
 *                   which avoids browser CORS restrictions.
 *  In production:   requests go directly to n8n (CORS is allowed from deployed origin).
 */
const IS_DEV  = import.meta.env.DEV;
const N8N_URL = IS_DEV
  ? "/api/n8n"                                             // proxied by vite.config.js
  : import.meta.env.VITE_API_URL;                         // loaded from Vercel environment variables

/** FALLBACK: Google Gemini 2.0 Flash ΓÇö question + hint generation */
const GEMINI_API_KEY = import.meta.env.VITE_GEMINI_API_KEY;
const GEMINI_URL = `https://generativelanguage.googleapis.com/v1beta/models/gemini-2.0-flash:generateContent?key=${GEMINI_API_KEY}`;

/** FALLBACK: Groq ΓÇö answer evaluation (6 000 free req/day) */
const GROQ_API_KEY  = import.meta.env.VITE_GROQ_API_KEY;
const GROQ_URL      = "https://api.groq.com/openai/v1/chat/completions";
const GROQ_MODEL    = "llama-3.1-8b-instant";

/** FALLBACK: NewsAPI ΓÇö tech headlines */
const NEWS_API_KEY = import.meta.env.VITE_NEWS_API_KEY;
const NEWS_URL     = `https://newsapi.org/v2/top-headlines?category=technology&pageSize=5&language=en&apiKey=${NEWS_API_KEY}`;

// ΓöÇΓöÇ Local fallback question bank ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
// Used as last resort when both n8n AND Gemini are unavailable.

const FALLBACK_QUESTIONS = [
  {
    question:
      "Given an array of integers, find two numbers such that they add up to a specific target. Return the indices of the two numbers. Each input has exactly one solution, and you may not use the same element twice. Example: nums = [2, 7, 11, 15], target = 9 ΓåÆ Output: [0, 1]",
    hint:
      "Use a hash map to store each number and its index as you iterate. For each number, check if (target - current number) already exists in the map.",
  },
  {
    question:
      "Given a string s, find the length of the longest substring without repeating characters. Example: s = 'abcabcbb' ΓåÆ Output: 3 (the answer is 'abc').",
    hint:
      "Use the sliding window technique with two pointers and a Set to track characters in the current window. Shrink the left pointer when a duplicate is found.",
  },
  {
    question:
      "Reverse a linked list. Given the head of a singly linked list, reverse the list and return the reversed list. Example: 1ΓåÆ2ΓåÆ3ΓåÆ4ΓåÆ5 ΓåÆ 5ΓåÆ4ΓåÆ3ΓåÆ2ΓåÆ1",
    hint:
      "Iterate through the list keeping track of three pointers: prev (null initially), curr (head), and next. At each step, reverse the link and advance all three pointers.",
  },
  {
    question:
      "Given a binary tree, return its maximum depth. The maximum depth is the number of nodes along the longest path from the root node down to the farthest leaf node.",
    hint:
      "Use DFS recursion. The depth of a node is 1 + max(depth of left child, depth of right child). Base case: null node returns 0.",
  },
  {
    question:
      "Given an integer array nums, return all the triplets [nums[i], nums[j], nums[k]] such that i Γëá j, i Γëá k, j Γëá k, and nums[i] + nums[j] + nums[k] == 0. The solution set must not contain duplicate triplets.",
    hint:
      "Sort the array first, then use a fixed pointer i and a two-pointer approach (left, right) for the remaining pair. Skip duplicates by checking if current element equals previous.",
  },
  {
    question:
      "Design a stack that supports push, pop, top, and retrieving the minimum element in constant time O(1). Implement the MinStack class.",
    hint:
      "Maintain two stacks: one for regular values and one to track minimums. Push to the min stack only when the new value is Γëñ the current minimum.",
  },
  {
    question:
      "Given a string containing just the characters '(', ')', '{', '}', '[' and ']', determine if the input string is valid. An input string is valid if every open bracket is closed by the same type of bracket in the correct order.",
    hint:
      "Use a stack. Push opening brackets onto the stack. For closing brackets, check if the stack's top matches ΓÇö if not, return false. Valid if stack is empty at end.",
  },
];

function getRandomFallback() {
  return FALLBACK_QUESTIONS[Math.floor(Math.random() * FALLBACK_QUESTIONS.length)];
}

// ΓöÇΓöÇ Fallback news (shown when n8n AND NewsAPI are both unavailable) ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

const FALLBACK_NEWS = [
  { title: "OpenAI releases new reasoning model with improved capabilities",            source: "TechCrunch", url: "", time: "" },
  { title: "Google DeepMind announces breakthrough in protein structure prediction",    source: "Nature",     url: "", time: "" },
  { title: "Meta open-sources new AI coding assistant for developers",                 source: "The Verge",  url: "", time: "" },
  { title: "Microsoft Azure expands AI services with new developer tools",             source: "ZDNet",      url: "", time: "" },
  { title: "Stack Overflow: TypeScript overtakes JavaScript in developer preference",  source: "InfoQ",      url: "", time: "" },
];

// ΓöÇΓöÇ Firestore cache helpers ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

function getTodayKey() {
  return new Date().toISOString().split("T")[0];
}

function getDailyContentRef() {
  return doc(db, "dailyContent", getTodayKey());
}

// ΓöÇΓöÇ 1. PRIMARY: n8n Webhook ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

/**
 * Fetches a coding question, hint, and news string from the n8n webhook.
 *
 * The webhook returns: { question: string, hint: string, news: string }
 *
 * @returns {{ question, hint, news } | null}  null = request failed / invalid
 */
async function fetchFromN8N() {
  try {
    console.log("Fetching from n8n...");
    // Append a timestamp to completely bust the browser's HTTP GET cache.
    // Without this, "Force Refresh" appears to fail because the browser simply returns the previous identical network response! 
    const fetchUrl = `${N8N_URL}${N8N_URL.includes("?") ? "&" : "?"}t=${Date.now()}`;
    const response = await fetch(fetchUrl, {
      method: "GET", // Changing to GET as it's often better for generic webhooks and sometimes avoids CORS pre-flight
      headers: { "Content-Type": "application/json" },
      cache: "no-store",
    });

    if (!response.ok) {
      console.warn(`ΓÜá∩╕Å  n8n webhook returned HTTP ${response.status} ΓÇö will use fallback.`);
      return null;
    }

    const data = await response.json();

    // Validate that the response has the expected fields
    if (!data?.question || !data?.hint) {
      console.warn("ΓÜá∩╕Å  n8n response missing required fields (question/hint) ΓÇö will use fallback.", data);
      return null;
    }

    console.log("API DATA:", data);
    return {
      question: String(data.question).trim(),
      hint:     String(data.hint).trim(),
      news:     data.news ? String(data.news).trim() : null,
    };
  } catch (err) {
    console.warn("ΓÜá∩╕Å  n8n fetch error ΓÇö will use fallback:", err.message);
    return null;
  }
}

/**
 * Converts the n8n plain-text news string into the articles array format
 * used everywhere in the UI.
 *
 * If the string looks like it contains multiple headlines separated by
 * newlines or numbered lists, each line becomes its own article card.
 *
 * @param {string} newsText
 * @returns {Array<{title, source, url, time}>}
 */
function parseN8NNews(newsText) {
  if (!newsText) return FALLBACK_NEWS;

  // Split on newlines and clean up numbered-list prefixes like "1. " or "- "
  const lines = newsText
    .split(/\n+/)
    .map((l) => l.replace(/^\s*[\d]+[.)]\s*|^[-ΓÇó*]\s*/, "").trim())
    .filter((l) => l.length > 8); // drop very short / empty lines

  if (lines.length === 0) {
    // Treat the whole string as a single headline
    return [{ title: newsText, source: "PrepFlow AI", url: "", time: "" }];
  }

  return lines.map((title) => ({ title, source: "PrepFlow AI", url: "", time: "" }));
}

// ΓöÇΓöÇ 2. FALLBACK: Google Gemini AI ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

/**
 * Generates a coding question + hint using Gemini 2.0 Flash.
 * Only called when n8n is unavailable.
 *
 * @param {string} topic   - e.g. "Arrays", "Any"
 * @param {string} company - e.g. "Google", "Any"
 * @returns {{ question, hint, difficulty, topic, company }}
 */
async function fetchQuestionFromGemini(topic = "Any", company = "Any") {
  const topicClause   = topic   && topic   !== "Any" ? ` about ${topic}`             : "";
  const companyClause = company && company !== "Any" ? ` commonly asked at ${company}` : "";

  const prompt = `You are a coding interview assistant. Generate ONE coding interview question${topicClause}${companyClause} suitable for a software engineering interview (algorithm or data structures). Also provide a helpful hint that guides without giving away the solution.

Respond ONLY with valid JSON (no markdown, no extra text):
{
  "question": "The full question text here",
  "hint": "A helpful hint here",
  "difficulty": "Easy" or "Medium" or "Hard",
  "topic": "exact topic e.g. Arrays, Trees, Dynamic Programming, Graphs, Strings, Sorting, Hashing, Two Pointers, Binary Search, Stack",
  "company": "${company !== "Any" ? company : "Google"}"
}`;

  try {
    const response = await fetch(GEMINI_URL, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        contents: [{ parts: [{ text: prompt }] }],
        generationConfig: { temperature: 0.85, maxOutputTokens: 600 },
      }),
    });

    if (!response.ok) {
      console.warn(`ΓÜá∩╕Å  Gemini API error ${response.status} ΓÇö using fallback question.`);
      return { ...getRandomFallback(), difficulty: "Medium", topic: topic || "General", company: company || "General" };
    }

    const result  = await response.json();
    const rawText = result?.candidates?.[0]?.content?.parts?.[0]?.text ?? "";
    const cleaned = rawText.replace(/```json|```/g, "").trim();

    const parsed = JSON.parse(cleaned);
    const fallback = getRandomFallback();
    return {
      question:   parsed.question   || fallback.question,
      hint:       parsed.hint       || fallback.hint,
      difficulty: parsed.difficulty || "Medium",
      topic:      parsed.topic      || topic  || "General",
      company:    parsed.company    || company || "General",
    };
  } catch {
    console.warn("Gemini response parse failed ΓÇö using local fallback.");
    return { ...getRandomFallback(), difficulty: "Medium", topic: topic || "General", company: company || "General" };
  }
}

// ΓöÇΓöÇ 3. FALLBACK: NewsAPI ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

function parseNewsAPIArticles(articles) {
  return articles
    .filter((a) => a.title && a.title !== "[Removed]")
    .map((a) => ({
      title:  a.title,
      source: a.source?.name || "Unknown",
      url:    a.url  || "",
      time:   a.publishedAt
        ? new Date(a.publishedAt).toLocaleTimeString("en-US", { hour: "2-digit", minute: "2-digit" })
        : "",
    }));
}

async function fetchNewsArticles() {
  try {
    const res  = await fetch(NEWS_URL);
    if (!res.ok) throw new Error(`NewsAPI HTTP ${res.status}`);
    const data   = await res.json();
    const parsed = parseNewsAPIArticles(data?.articles || []);
    return parsed.length > 0 ? parsed : FALLBACK_NEWS;
  } catch (err) {
    console.warn("NewsAPI failed ΓÇö using fallback:", err.message);
    return FALLBACK_NEWS;
  }
}

// ΓöÇΓöÇ Public: Refresh news (used by Dashboard refresh button) ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

/**
 * Fetches fresh news articles on demand.
 * Tries n8n first, then NewsAPI, then local fallback.
 * Does NOT read/write Firestore cache.
 *
 * @returns {Promise<Array<{title, source, url, time}>>}
 */
export async function fetchMoreNews() {
  // Try n8n for fresh news
  const n8nData = await fetchFromN8N();
  if (n8nData?.news) return parseN8NNews(n8nData.news);

  // Fall back to NewsAPI
  return fetchNewsArticles();
}

// ΓöÇΓöÇ Main export: Dashboard data ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

/**
 * Fetches today's full dashboard content.
 *
 * Priority:
 *   1. n8n webhook      (primary live source)
 *   2. Gemini + NewsAPI (fallback if n8n fails)
 *
 * @param {string} topic   - Filter topic,   "Any" = no filter
 * @param {string} company - Filter company, "Any" = no filter
 * @returns {{ question, hint, difficulty, topic, company, articles[], news }}
 */
export async function fetchDashboardData(topic = "Any", company = "Any", force = false) {
  const today = new Date().toISOString().split("T")[0];
  const isFiltered = topic !== "Any" || company !== "Any";

  // ΓöÇΓöÇ 1. LOCAL STORAGE LOGIC & DATE COMPARISON ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  if (!isFiltered && !force) {
    try {
      const stored = localStorage.getItem("prepflow_daily_data");
      if (stored) {
        const parsedData = JSON.parse(stored);

        // Date comparison logic: Only use stored data if date exactly matches today
        if (parsedData.date === today && parsedData.question && parsedData.hint) {
          console.log("≡ƒôª Loaded exact same question from localStorage cache for today.");
          return {
            question:   parsedData.question,
            hint:       parsedData.hint,
            news:       parsedData.news || "",
            articles:   parsedData.news ? parseN8NNews(parsedData.news) : parseN8NNews(""),
            difficulty: parsedData.difficulty || "Medium",
            topic:      parsedData.topic      || "General",
            company:    parsedData.company    || "General",
          };
        }
      }
    } catch (err) {
      console.warn("localStorage read failed, corrupted data. Fetching new...", err);
      localStorage.removeItem("prepflow_daily_data");
    }
  }

  // ΓöÇΓöÇ 2. API FETCH CONDITION (Only if different date, forced, or filtered) ΓöÇΓöÇ
  console.log("≡ƒöä Fetching fresh question from n8n...");
  let question, hint, difficulty, returnedTopic, returnedCompany, articles, newsRaw;

  // We skip n8n if filtered because n8n webhook currently returns generic random questions
  const n8nResult = isFiltered ? null : await fetchFromN8N();

  if (n8nResult) {
    // Γ£à n8n succeeded ΓÇö use its question, hint, and news
    question         = n8nResult.question;
    hint             = n8nResult.hint;
    newsRaw          = n8nResult.news;
    difficulty       = "Medium";       // n8n doesn't return difficulty
    returnedTopic    = topic  !== "Any" ? topic   : "General";
    returnedCompany  = company !== "Any" ? company : "General";
    articles         = parseN8NNews(n8nResult.news);
  } else {
    // ΓöÇΓöÇ Fallback ΓÇö Gemini AI + NewsAPI ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
    console.log("Γå⌐∩╕Å  Falling back to Gemini + NewsAPI...");
    const [questionData, newsArticles] = await Promise.all([
      fetchQuestionFromGemini(topic, company),
      fetchNewsArticles(),
    ]);

    question        = questionData.question;
    hint            = questionData.hint;
    newsRaw         = "";
    difficulty      = questionData.difficulty    || "Medium";
    returnedTopic   = questionData.topic         || topic   || "General";
    returnedCompany = questionData.company       || company || "General";
    articles        = newsArticles;
  }

  // ΓöÇΓöÇ 3. SAVE NEW DATA + TODAY'S DATE IN LOCALSTORAGE ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  if (!isFiltered) {
    try {
      const dailyData = {
        date: today,
        question,
        hint,
        news: newsRaw || "",
        difficulty,
        topic: returnedTopic,
        company: returnedCompany
      };
      localStorage.setItem("prepflow_daily_data", JSON.stringify(dailyData));
      console.log("≡ƒÆ╛ Saved new question + today's date in localStorage.");
    } catch (saveErr) {
      console.warn("Failed to set localStorage (quota exceeded?):", saveErr.message);
    }

    // As a backup, we still securely save user analytics to Firestore
    try {
      await setDoc(getDailyContentRef(), {
        question, hint, articles, difficulty, news: newsRaw,
        topic:       returnedTopic,
        company:     returnedCompany,
        generatedAt: serverTimestamp(),
        source:      n8nResult ? "n8n" : "gemini",
      });
    } catch (saveErr) {}
  }

  return { question, hint, articles, difficulty, news: newsRaw, topic: returnedTopic, company: returnedCompany };
}

// ΓöÇΓöÇ Answer Checker (Groq ΓÇö LLaMA 3.1 8B Instant) ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
// No changes ΓÇö Groq is independent of the question source.

/**
 * Evaluates a user's answer (code or plain English) via Groq's LLaMA model.
 *
 * @param {string} question  - The coding question text
 * @param {string} answer    - The user's code or English explanation
 * @param {string} mode      - "code" | "english"
 * @param {string} language  - Programming language (for code mode)
 * @returns {Promise<{correct: boolean|null, feedback: string, suggestion: string}>}
 */
export async function checkAnswer(question, answer, mode = "code", language = "javascript") {
  if (!GROQ_API_KEY || GROQ_API_KEY === "YOUR_GROQ_API_KEY") {
    return {
      correct:    null,
      feedback:   "Add your free Groq API key to the .env file (VITE_GROQ_API_KEY) to enable answer checking. Get one free at console.groq.com",
      suggestion: "",
    };
  }

  const modeLabel    = mode === "code" ? `${language} code solution` : "plain English explanation of the approach";
  const systemPrompt = `You are a coding interview evaluator. Evaluate answers concisely and accurately. Always respond with valid JSON only ΓÇö no markdown, no extra text.`;
  const userPrompt   = `Question: ${question}

User's ${modeLabel}:
${answer}

Evaluate this answer. Respond ONLY with this JSON:
{"correct": true_or_false, "feedback": "2-3 sentences on correctness and quality", "suggestion": "one improvement tip or empty string if perfect"}`;

  try {
    const response = await fetch(GROQ_URL, {
      method:  "POST",
      headers: {
        "Content-Type":  "application/json",
        "Authorization": `Bearer ${GROQ_API_KEY}`,
      },
      body: JSON.stringify({
        model:           GROQ_MODEL,
        messages:        [
          { role: "system", content: systemPrompt },
          { role: "user",   content: userPrompt },
        ],
        temperature:     0.3,
        max_tokens:      400,
        response_format: { type: "json_object" },
      }),
    });

    if (!response.ok) {
      const errText = await response.text().catch(() => "");
      console.warn(`Groq error ${response.status}:`, errText);
      return {
        correct:    null,
        feedback:   response.status === 429
          ? "Rate limit hit. Please wait a moment and try again."
          : "Evaluation service unavailable. Please try again.",
        suggestion: "",
      };
    }

    const result  = await response.json();
    const rawText = result?.choices?.[0]?.message?.content ?? "{}";
    const parsed  = JSON.parse(rawText);

    return {
      correct:    parsed.correct    ?? null,
      feedback:   parsed.feedback   || "No feedback available.",
      suggestion: parsed.suggestion || "",
    };
  } catch (err) {
    console.error("checkAnswer error:", err);
    return {
      correct:    null,
      feedback:   "Evaluation failed ΓÇö check your internet connection and try again.",
      suggestion: "",
    };
  }
}

// Firestore database helpers for per-user, per-day progress tracking
// Data is stored at: users/{userId}/days/{YYYY-MM-DD}
//
// Schema for each day's document:
// {
//   solved: boolean,       ΓÇö whether the user marked today's question solved
//   hintsUsed: number,     ΓÇö how many times hint was shown (0 or 1)
//   streak: number,        ΓÇö current streak count
//   lastUpdated: timestamp ΓÇö Firestore server timestamp
// }

import { db } from "./firebase";
import {
  doc,
  getDoc,
  setDoc,
  updateDoc,
  serverTimestamp,
  increment,
} from "firebase/firestore";

// ΓöÇΓöÇΓöÇ Helpers ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

/**
 * Returns today's date as a string like "2026-03-20" (used as Firestore doc ID)
 */
function getTodayKey() {
  return new Date().toISOString().split("T")[0];
}

/**
 * Returns the Firestore document reference for a user's day
 * Path: users/{userId}/days/{YYYY-MM-DD}
 */
function getDayRef(userId) {
  const today = getTodayKey();
  return doc(db, "users", userId, "days", today);
}

/**
 * Returns the top-level user document reference
 * Path: users/{userId}
 */
function getUserRef(userId) {
  return doc(db, "users", userId);
}

// ΓöÇΓöÇΓöÇ Read ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

/**
 * Load today's progress for a user.
 * Returns: { solved, hintsUsed, streak } or default values if no record yet.
 */
export async function getDayProgress(userId) {
  try {
    const daySnap = await getDoc(getDayRef(userId));
    const userSnap = await getDoc(getUserRef(userId));

    const dayData = daySnap.exists() ? daySnap.data() : {};
    const userData = userSnap.exists() ? userSnap.data() : {};

    return {
      solved: dayData.solved ?? false,
      hintsUsed: dayData.hintsUsed ?? 0,
      streak: userData.streak ?? 0,
    };
  } catch (err) {
    console.error("Firestore read error:", err);
    // Return safe defaults so the UI doesn't break
    return { solved: false, hintsUsed: 0, streak: 0 };
  }
}

// ΓöÇΓöÇΓöÇ Write ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

/**
 * Mark today's question as solved and update the streak.
 * Increments streak only once per day.
 */
export async function markSolved(userId, currentStreak) {
  try {
    const dayRef = getDayRef(userId);
    const daySnap = await getDoc(dayRef);

    // Write or update today's day doc
    if (daySnap.exists()) {
      await updateDoc(dayRef, { solved: true, lastUpdated: serverTimestamp() });
    } else {
      // First activity today ΓÇö also increment streak
      await setDoc(dayRef, {
        solved: true,
        hintsUsed: 0,
        lastUpdated: serverTimestamp(),
      });
      // Increment streak on the top-level user doc
      await setDoc(
        getUserRef(userId),
        { streak: increment(1) },
        { merge: true }
      );
    }
  } catch (err) {
    console.error("Firestore write error (markSolved):", err);
  }
}

/**
 * Unmark today's question as solved (toggle back).
 * Does NOT decrement the streak.
 */
export async function unmarkSolved(userId) {
  try {
    const dayRef = getDayRef(userId);
    const daySnap = await getDoc(dayRef);
    if (daySnap.exists()) {
      await updateDoc(dayRef, { solved: false, lastUpdated: serverTimestamp() });
    }
  } catch (err) {
    console.error("Firestore write error (unmarkSolved):", err);
  }
}

/**
 * Record that the user viewed the hint today.
 */
export async function recordHintUsed(userId) {
  try {
    const dayRef = getDayRef(userId);
    const daySnap = await getDoc(dayRef);

    if (daySnap.exists()) {
      await updateDoc(dayRef, { hintsUsed: 1, lastUpdated: serverTimestamp() });
    } else {
      await setDoc(dayRef, {
        solved: false,
        hintsUsed: 1,
        lastUpdated: serverTimestamp(),
      });
    }
  } catch (err) {
    console.error("Firestore write error (recordHintUsed):", err);
  }
}

// ΓöÇΓöÇΓöÇ Progress History ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

/**
 * Get all day documents for a user (for heatmap + history).
 * Returns array of { date: "YYYY-MM-DD", solved, hintsUsed, topic, question }
 */
export async function getAllDays(userId) {
  try {
    const { collection, getDocs } = await import("firebase/firestore");
    const daysRef = collection(db, "users", userId, "days");
    const snap = await getDocs(daysRef);
    return snap.docs.map((d) => ({ date: d.id, ...d.data() }));
  } catch (err) {
    console.error("getAllDays error:", err);
    return [];
  }
}

// ΓöÇΓöÇΓöÇ Bookmarks ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

function getBookmarkRef(userId, bookmarkId) {
  return doc(db, "users", userId, "bookmarks", bookmarkId);
}

/**
 * Add a bookmark for a question.
 * @param {string} userId
 * @param {{ question, hint, difficulty, topic, company }} data
 */
export async function addBookmark(userId, data) {
  try {
    const id = `bm_${Date.now()}`;
    await setDoc(getBookmarkRef(userId, id), {
      ...data,
      savedAt: serverTimestamp(),
    });
    return id;
  } catch (err) {
    console.error("addBookmark error:", err);
    return null;
  }
}

/**
 * Remove a bookmark by its document ID.
 */
export async function removeBookmark(userId, bookmarkId) {
  try {
    const { deleteDoc } = await import("firebase/firestore");
    await deleteDoc(getBookmarkRef(userId, bookmarkId));
  } catch (err) {
    console.error("removeBookmark error:", err);
  }
}

/**
 * Get all bookmarks for a user.
 * Returns array of { id, question, hint, difficulty, topic, company, savedAt }
 */
export async function getBookmarks(userId) {
  try {
    const { collection, getDocs, orderBy, query } = await import("firebase/firestore");
    const ref = collection(db, "users", userId, "bookmarks");
    const q = query(ref, orderBy("savedAt", "desc"));
    const snap = await getDocs(q);
    return snap.docs.map((d) => ({ id: d.id, ...d.data() }));
  } catch (err) {
    console.error("getBookmarks error:", err);
    return [];
  }
}

